(function (global) {
  function drawLine(ctx, chart, annotation) {
    var xScale = chart.scales && chart.scales.x;
    if (!xScale) return;

    var label = annotation.label || {};
    var xValue = annotation.xMin;
    if (xValue === undefined || xValue === null) return;

    var labels = (chart.data && chart.data.labels) || [];
    var index = labels.findIndex(function (item) {
      return String(item) === String(xValue);
    });
    var x = xScale.getPixelForValue(index >= 0 ? index : xValue);
    var area = chart.chartArea;

    ctx.save();
    ctx.beginPath();
    ctx.strokeStyle = annotation.borderColor || "#00ffff";
    ctx.lineWidth = annotation.borderWidth || 2;
    ctx.moveTo(x, area.top);
    ctx.lineTo(x, area.bottom);
    ctx.stroke();

    if (label.display) {
      var text = label.content || "";
      ctx.font = label.font || "12px Arial";
      ctx.fillStyle = label.color || "#00ffff";
      ctx.textAlign = "left";
      ctx.textBaseline = "top";
      var padding = 4;
      var textX = x + 6;
      var textY = area.top + 6;
      var metrics = ctx.measureText(text);
      var boxW = metrics.width + padding * 2;
      var boxH = 16 + padding * 2;
      ctx.fillStyle = label.backgroundColor || "#000000";
      ctx.fillRect(textX, textY, boxW, boxH);
      ctx.fillStyle = label.color || "#00ffff";
      ctx.fillText(text, textX + padding, textY + padding);
    }

    ctx.restore();
  }

  var plugin = {
    id: "annotation",
    afterDraw: function (chart) {
      var options = chart.options && chart.options.plugins && chart.options.plugins.annotation;
      if (!options || !options.annotations) return;

      var ctx = chart.ctx;
      Object.keys(options.annotations).forEach(function (key) {
        var annotation = options.annotations[key];
        if (annotation && annotation.type === "line") {
          drawLine(ctx, chart, annotation);
        }
      });
    }
  };

  global.ChartAnnotationPlugin = plugin;
  if (global.Chart && typeof global.Chart.register === "function") {
    global.Chart.register(plugin);
  }
})(window);
